-- ============================================================
-- TEST SUMMARY REPORT
-- ============================================================
SELECT
    '========== TEST EXECUTION SUMMARY ==========' AS header
UNION ALL
SELECT
    'Total tests: ' || COUNT(*)::VARCHAR ||
    ' | PASS: ' || SUM(CASE WHEN result = 'PASS' THEN 1 ELSE 0 END)::VARCHAR ||
    ' | FAIL: ' || SUM(CASE WHEN result = 'FAIL' THEN 1 ELSE 0 END)::VARCHAR ||
    ' | ERROR: ' || SUM(CASE WHEN result = 'ERROR' THEN 1 ELSE 0 END)::VARCHAR
FROM test_execution_log;

-- Detail of any failures:
SELECT test_id, test_name, actual_value, expected_value, result, error_message
FROM test_execution_log
WHERE result <> 'PASS'
ORDER BY test_id;

-- Category breakdown:
SELECT
    ter.test_category,
    COUNT(*)                                            AS total_tests,
    SUM(CASE WHEN tel.result = 'PASS' THEN 1 ELSE 0 END) AS pass_count,
    SUM(CASE WHEN tel.result = 'FAIL' THEN 1 ELSE 0 END) AS fail_count
FROM test_execution_log tel
INNER JOIN test_expected_results ter ON ter.test_id = tel.test_id
GROUP BY ter.test_category
ORDER BY ter.test_category;
